import { useEffect, useMemo, useState } from "react";
import {
  Badge,
  Button,
  Card,
  Col,
  Container,
  Form,
  InputGroup,
  Pagination,
  Row,
  Spinner,
} from "react-bootstrap";
import { useLocation, useNavigate } from "react-router-dom";
import api from "../services/api";

const PAGE_SIZE = 6;

function HomePage() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedTab, setSelectedTab] = useState("all");
  const [searchTerm, setSearchTerm] = useState("");
  const [currentPage, setCurrentPage] = useState(1);

  const location = useLocation();
  const navigate = useNavigate();

  const getStoredUser = () => {
    try {
      const rawUser = localStorage.getItem("user");
      if (!rawUser || rawUser === "undefined") return null;
      return JSON.parse(rawUser);
    } catch (error) {
      localStorage.removeItem("user");
      return null;
    }
  };

  const user = getStoredUser();

  const getBannerSrc = (bannerImage) => {
    if (!bannerImage) {
      return "https://images.unsplash.com/photo-1501386761578-eac5c94b800a?auto=format&fit=crop&w=1200&q=80";
    }

    if (bannerImage.startsWith("http://") || bannerImage.startsWith("https://")) {
      return bannerImage;
    }

    return `/images/${bannerImage}`;
  };

  const formatDate = (value) => {
    if (!value) return "Chưa cập nhật thời gian";
    return new Date(value).toLocaleString("vi-VN", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  const getMinPrice = (event) => {
    const candidates = [event?.min_price, event?.price_from, event?.price];
    const found = candidates.find(
      (item) => item !== undefined && item !== null && item !== ""
    );
    return Number(found || 0);
  };

  const getStatusLabel = (status) => {
    switch (status) {
      case "on_sale":
        return "Đang mở bán";
      case "upcoming":
        return "Sắp diễn ra";
      case "ended":
        return "Đã kết thúc";
      case "sold_out":
        return "Hết vé";
      case "paused":
        return "Tạm dừng";
      default:
        return "Đang cập nhật";
    }
  };

  const getStatusVariant = (status) => {
    switch (status) {
      case "on_sale":
        return "success";
      case "upcoming":
        return "warning";
      case "ended":
      case "sold_out":
        return "secondary";
      case "paused":
        return "danger";
      default:
        return "dark";
    }
  };

  useEffect(() => {
    const query = new URLSearchParams(location.search).get("q") || "";
    setSearchTerm(query);
  }, [location.search]);

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const response = await api.get("/events");

        const eventData = Array.isArray(response.data)
          ? response.data
          : Array.isArray(response.data?.data)
          ? response.data.data
          : [];

        setEvents(eventData);
      } catch (error) {
        console.error("Lỗi khi tải sự kiện:", error);
        setEvents([]);
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, []);

  const featuredEvent = useMemo(() => {
    if (!events.length) return null;
    return (
      events.find((item) => item.status === "on_sale") ||
      events.find((item) => item.status === "upcoming") ||
      events[0]
    );
  }, [events]);

  const filteredEvents = useMemo(() => {
    const keyword = searchTerm.trim().toLowerCase();

    return events.filter((event) => {
      const matchesTab =
        selectedTab === "all"
          ? ["on_sale", "upcoming", "ended", "sold_out", "paused"].includes(event.status)
          : selectedTab === "ended"
          ? ["ended", "sold_out"].includes(event.status)
          : event.status === selectedTab;

      const haystack = [event.title, event.location, event.description]
        .filter(Boolean)
        .join(" ")
        .toLowerCase();

      const matchesSearch = !keyword || haystack.includes(keyword);
      return matchesTab && matchesSearch;
    });
  }, [events, searchTerm, selectedTab]);

  const totalPages = Math.max(1, Math.ceil(filteredEvents.length / PAGE_SIZE));

  useEffect(() => {
    if (currentPage > totalPages) setCurrentPage(1);
  }, [currentPage, totalPages]);

  const paginatedEvents = useMemo(() => {
    const start = (currentPage - 1) * PAGE_SIZE;
    return filteredEvents.slice(start, start + PAGE_SIZE);
  }, [filteredEvents, currentPage]);

  const stats = useMemo(() => {
    return {
      all: events.length,
      on_sale: events.filter((item) => item.status === "on_sale").length,
      upcoming: events.filter((item) => item.status === "upcoming").length,
      ended: events.filter((item) => ["ended", "sold_out"].includes(item.status)).length,
    };
  }, [events]);

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    const params = new URLSearchParams();
    if (searchTerm.trim()) params.set("q", searchTerm.trim());
    navigate(`/home${params.toString() ? `?${params.toString()}` : ""}`);
    setCurrentPage(1);
  };

  const tabOptions = [
    { key: "all", label: "Tất cả", count: stats.all },
    { key: "on_sale", label: "Đang mở bán", count: stats.on_sale },
    { key: "upcoming", label: "Sắp diễn ra", count: stats.upcoming },
    { key: "ended", label: "Đã kết thúc", count: stats.ended },
  ];

  return (
    <Container className="page-shell">
      <section className="hero-ticket mb-5">
        <Row className="align-items-center g-4">
          <Col lg={7}>
            <div className="hero-tag">Nền tảng bán vé chuyên nghiệp</div>
            <h1 className="hero-title">
              Khám phá concert hot, mua vé nhanh và quản lý đơn hàng hiện đại.
            </h1>
            <p className="hero-desc">
              Giao diện mới tập trung vào trải nghiệm người dùng: banner lớn,
              card sự kiện rõ ràng, bộ lọc trực quan và flow xem chi tiết đẹp hơn.
            </p>

            <div className="hero-chips">
              <span className="hero-chip">🎤 Concert nổi bật</span>
              <span className="hero-chip">🎫 Đặt vé nhanh</span>
              <span className="hero-chip">⚡ Giao diện hiện đại</span>
            </div>
          </Col>

          <Col lg={5}>
            <Card className="glass-card border-0">
              <Card.Body className="p-4">
                <div className="fw-bold fs-5 mb-3">Tìm sự kiện phù hợp với bạn</div>

                <Form onSubmit={handleSearchSubmit}>
                  <InputGroup className="mb-3">
                    <Form.Control
                      placeholder="Tên sự kiện, nghệ sĩ, địa điểm"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </InputGroup>

                  <div className="mini-stats">
                    <div>
                      <strong>{stats.on_sale}</strong>
                      <span>Đang mở bán</span>
                    </div>
                    <div>
                      <strong>{stats.upcoming}</strong>
                      <span>Sắp diễn ra</span>
                    </div>
                    <div>
                      <strong>{stats.ended}</strong>
                      <span>Đã kết thúc</span>
                    </div>
                  </div>

                  <Button type="submit" className="btn-brand w-100 mt-3">
                    Tìm kiếm sự kiện
                  </Button>
                </Form>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      </section>

      {featuredEvent && (
        <section className="mb-5">
          <div className="section-head">
            <div>
              <div className="section-tag">Sự kiện nổi bật</div>
              <h2 className="section-title">Đề xuất hôm nay</h2>
            </div>
          </div>

          <Card className="featured-card border-0 overflow-hidden">
            <Row className="g-0">
              <Col lg={6}>
                <div className="featured-image-wrap">
                  <img
                    src={getBannerSrc(featuredEvent.banner_image)}
                    alt={featuredEvent.title}
                    className="featured-image"
                  />
                </div>
              </Col>

              <Col lg={6}>
                <Card.Body className="p-4 p-lg-5">
                  <Badge bg={getStatusVariant(featuredEvent.status)} className="rounded-pill px-3 py-2 mb-3">
                    {getStatusLabel(featuredEvent.status)}
                  </Badge>

                  <h3 className="featured-title">{featuredEvent.title}</h3>
                  <p className="text-muted">
                    {featuredEvent.description ||
                      "Sự kiện đang được đề xuất nổi bật trên hệ thống. Xem chi tiết để chọn loại vé phù hợp."}
                  </p>

                  <div className="featured-grid">
                    <div className="featured-item">
                      <span>Thời gian</span>
                      <strong>{formatDate(featuredEvent.start_time || featuredEvent.event_date)}</strong>
                    </div>
                    <div className="featured-item">
                      <span>Địa điểm</span>
                      <strong>{featuredEvent.location || "Đang cập nhật"}</strong>
                    </div>
                    <div className="featured-item">
                      <span>Giá từ</span>
                      <strong>{getMinPrice(featuredEvent).toLocaleString("vi-VN")} VND</strong>
                    </div>
                    <div className="featured-item">
                      <span>Trạng thái</span>
                      <strong>{getStatusLabel(featuredEvent.status)}</strong>
                    </div>
                  </div>

                  <div className="d-flex gap-2 flex-wrap mt-4">
                    <Button className="btn-brand" onClick={() => navigate(`/event/${featuredEvent.id}`)}>
                      Xem chi tiết
                    </Button>
                    {user && (
                      <Button variant="outline-dark" className="rounded-pill px-4" onClick={() => navigate("/profile")}>
                        Vé của tôi
                      </Button>
                    )}
                  </div>
                </Card.Body>
              </Col>
            </Row>
          </Card>
        </section>
      )}

      <section>
        <div className="section-head mb-4">
          <div>
            <div className="section-tag">Khám phá sự kiện</div>
            <h2 className="section-title">Danh sách sự kiện</h2>
            <p className="text-muted mb-0">
              Chia theo trạng thái để người dùng tìm nhanh hơn.
            </p>
          </div>
        </div>

        <div className="toolbar-wrap">
          <div className="toolbar-tabs">
            {tabOptions.map((tab) => (
              <button
                key={tab.key}
                type="button"
                className={`toolbar-tab ${selectedTab === tab.key ? "active" : ""}`}
                onClick={() => {
                  setSelectedTab(tab.key);
                  setCurrentPage(1);
                }}
              >
                {tab.label}
                <span>{tab.count}</span>
              </button>
            ))}
          </div>

          <div className="toolbar-count">{filteredEvents.length} sự kiện phù hợp</div>
        </div>

        {loading ? (
          <div className="text-center py-5">
            <Spinner animation="border" />
          </div>
        ) : paginatedEvents.length === 0 ? (
          <Card className="glass-card border-0">
            <Card.Body className="text-center py-5">
              <h4 className="mb-2">Không có sự kiện phù hợp</h4>
              <p className="text-muted mb-3">Hãy thử từ khóa khác hoặc đổi bộ lọc.</p>
              <Button
                variant="outline-dark"
                className="rounded-pill px-4"
                onClick={() => {
                  setSearchTerm("");
                  setSelectedTab("all");
                  navigate("/home");
                }}
              >
                Xóa bộ lọc
              </Button>
            </Card.Body>
          </Card>
        ) : (
          <>
            <Row className="g-4">
              {paginatedEvents.map((event) => (
                <Col lg={4} md={6} key={event.id}>
                  <Card className="event-card-new h-100 border-0">
                    <div className="event-image-wrap">
                      <img
                        src={getBannerSrc(event.banner_image)}
                        alt={event.title}
                        className="event-image"
                      />
                      <Badge bg={getStatusVariant(event.status)} className="event-badge-floating">
                        {getStatusLabel(event.status)}
                      </Badge>
                    </div>

                    <Card.Body className="p-4 d-flex flex-column">
                      <div className="mb-3">
                        <div className="event-name clamp-2">{event.title}</div>
                        <div className="event-meta">📍 {event.location || "Đang cập nhật địa điểm"}</div>
                        <div className="event-meta">🗓 {formatDate(event.start_time || event.event_date)}</div>
                      </div>

                      <div className="text-muted clamp-3 mb-3">
                        {event.description || "Sự kiện đang được cập nhật mô tả chi tiết trên hệ thống."}
                      </div>

                      <div className="event-footer mt-auto">
                        <div>
                          <div className="price-label">Giá từ</div>
                          <div className="price-value">
                            {getMinPrice(event).toLocaleString("vi-VN")} VND
                          </div>
                        </div>

                        <Button className="btn-brand" onClick={() => navigate(`/event/${event.id}`)}>
                          Xem chi tiết
                        </Button>
                      </div>
                    </Card.Body>
                  </Card>
                </Col>
              ))}
            </Row>

            {totalPages > 1 && (
              <div className="pagination-wrap mt-4">
                <Pagination>
                  <Pagination.Prev
                    disabled={currentPage === 1}
                    onClick={() => setCurrentPage((prev) => Math.max(1, prev - 1))}
                  />
                  {Array.from({ length: totalPages }, (_, index) => index + 1).map((page) => (
                    <Pagination.Item
                      key={page}
                      active={page === currentPage}
                      onClick={() => setCurrentPage(page)}
                    >
                      {page}
                    </Pagination.Item>
                  ))}
                  <Pagination.Next
                    disabled={currentPage === totalPages}
                    onClick={() => setCurrentPage((prev) => Math.min(totalPages, prev + 1))}
                  />
                </Pagination>
              </div>
            )}
          </>
        )}
      </section>
    </Container>
  );
}

export default HomePage;
